    "\u6211\u53ef\u4ee5\u5e2e\u52a9\u9762\u8bd5\u5b66\u751f",
  "\u6211\u7684\u9762\u8bd5": "\u6211\u7684\u9762\u8bd5",
  "\u6211\u76f8\u4fe1\u8be5\u540c\u5b66\u53ef\u4ee5\u901a\u8fc7\u8fdc\u89c1\u5e73\u53f0\u83b7\u5f97\u5f88\u597d\u7684\u6210\u957f\u673a\u4f1a\u3002\u603b\u4f53\u6765\u8bf4\uff0c\u6211\u7684\u5224\u65ad\u57fa\u4e8e\u4ee5\u4e0b\u51e0\u70b9\u539f\u56e0\uff1ann- \u8be5\u540c\u5b66\u6709\u5f3a\u70c8\u7684\uff0c\u826f\u6027\u7684\u52a8\u673a\u3002\u5979\u5728\u8c08\u53ca\u5fd7\u613f\u8005\u6d3b\u52a8\u548c\u81ea\u5df1\u5f53\u8001\u5e08\u7684\u7406\u60f3\u65f6\u5145\u6ee1\u4e86\u5174\u594b\uff0c\u6210\u5c31\u611f\u548c\u8d23\u4efb\u611f\u3002\u53ef\u4ee5\u770b\u5230\u5979\u975e\u5e38\u5e0c\u671b\u627e\u5230\u4e00\u6761\u6e20\u9053\u6765\u5b9e\u73b0\u81ea\u5df1\u7684\u7406\u60f3\uff0c\u5e76\u4e14\u8fd9\u4e2a\u7406\u60f3\u5bf9\u793e\u4f1a\u662f\u5f88\u6709\u610f\u4e49\u7684\u3002n- \u8be5\u540c\u5b66\u6709\u81ea\u6211\u63d0\u5347\u7684\u6b32\u671b\u548c\u5b66\u4e60\u7684\u80fd\u529b\uff0c\u5979\u5bf9\u81ea\u5df1\u9700\u8981\u63d0\u5347\u7684\u5730\u65b9\u76f8\u5bf9\u6bd4\u8f83\u660e\u786e\uff0c\u5728\u5f88\u591a\u65b9\u9762\u4e5f\u5c55\u73b0\u51fa\u4e0d\u9519\u7684\u4fdd\u6301\u5b66\u4e60\u7684\u80fd\u529bn- \u8be5\u540c\u5b66\u8ba4\u53ef\u5bfc\u5e08\u5236\uff0c\u5979\u591a\u6b21\u63d0\u5230\u4e00\u4e2a\u597d\u8001\u5e08\u7684\u91cd\u8981\u6027\uff0c\u4ee5\u53ca\u5e0c\u671b\u81ea\u5df1\u4ee5\u540e\u7684\u4eba\u751f\u4e2d\u9047\u5230\u4e00\u4f4d\u597d\u5bfc\u5e08nn\u4ee5\u4e0a\u4e09\u70b9\u662f\u6211\u8ba4\u4e3a\u8be5\u540c\u5b66\u80fd\u591f\u901a\u8fc7\u8fdc\u89c1\u5bfc\u5e08\u5236\u6709\u6240\u6536\u83b7\u7684\u57fa\u7840\uff0c\u4e5f\u662f\u8fdc\u89c1\u80fd\u591f\u901a\u8fc7\u901a\u8fc7\u5e2e\u52a9\u8be5\u540c\u5b66\u800c\u60e0\u53ca\u793e\u4f1a\u7684\u57fa\u7840\u3002\u4e0b\u9762\u51e0\u70b9\u662f\u6211\u8ba4\u4e3a\u8fdc\u89c1\u53ef\u4ee5\u5177\u4f53\u5e2e\u52a9\u5230\u8be5\u540c\u5b66\u7684\u5730\u65b9\uff1an- \u603b\u4f53\u6765\u8bf4\uff0c\u8be5\u540c\u5b66\u7684\u516b\u4e2a\u7ef4\u5ea6\u5e76\u4e0d\u5b8c\u7f8e\uff0c\u5728\u67d0\u4e9b\u7ef4\u5ea6\u4e0a\u6709\u6bd4\u8f83\u5927\u7684\u8fdb\u6b65\u7a7a\u95f4n- \u4ece\u2019\u9053\u2018\u7684\u5c42\u9762\u800c\u8a00\uff0c\u8be5\u540c\u5b66\u7f3a\u4e4f\u5bf9\u793e\u4f1a\u73b0\u8c61\u7684\u7cfb\u7edf\u601d\u8003\uff0c\u5979\u5bf9\u8fd9\u4e9b\u95ee\u9898\u7684\u770b\u6cd5\u5f80\u5f80\u5c40\u9650\u5728\u4e2a\u4eba\u7ecf\u5386\u4e0a\u3002\u8fd9\u662f\u8fdc\u89c1\u5e73\u53f0\u53ef\u4ee5\u63d0\u4f9b\u5f88\u591a\u5f15\u5bfc\u7684\u5730\u65b9\u3002\u6211\u76f8\u4fe1\u5982\u679c\u8be5\u540c\u5b66\u80fd\u591f\u7ad9\u5728\u66f4\u9ad8\u7684\u89d2\u5ea6\u601d\u8003\u5979\u7684\u7ecf\u5386\uff0c\u5979\u7684\u8d23\u4efb\u611f\u53ef\u4ee5\u60e0\u53ca\u66f4\u591a\u7684\u4eba\u3002n- \u4ece\u2018\u672f\u2019\u7684\u5c42\u9762\u800c\u8a00\uff0c\u6211\u89c2\u5bdf\u5230\u8be5\u540c\u5b66\u7684\u4fe1\u606f\u6e20\u9053\u76f8\u5bf9\u6bd4\u8f83\u5355\u4e00\uff0c\u5f88\u591a\u4fe1\u606f\u6765\u81ea\u4e8e\u5bfc\u5e08\u548c\u8eab\u8fb9\u7684\u4eba\uff0c\u5bf9\u81ea\u5df1\u7684\u8ba4\u8bc6\u4e5f\u6709\u5f85\u6df1\u5165\u3002\u800c\u8fd9\u4e24\u70b9\u90fd\u662f\u6211\u4eec\u5bfc\u5e08\u5236\u7684\u5f3a\u9879\u3002":
    "\u6211\u76f8\u4fe1\u8be5\u540c\u5b66\u53ef\u4ee5\u901a\u8fc7\u8fdc\u89c1\u5e73\u53f0\u83b7\u5f97\u5f88\u597d\u7684\u6210\u957f\u673a\u4f1a\u3002\u603b\u4f53\u6765\u8bf4\uff0c\u6211\u7684\u5224\u65ad\u57fa\u4e8e\u4ee5\u4e0b\u51e0\u70b9\u539f\u56e0\uff1ann- \u8be5\u540c\u5b66\u6709\u5f3a\u70c8\u7684\uff0c\u826f\u6027\u7684\u52a8\u673a\u3002\u5979\u5728\u8c08\u53ca\u5fd7\u613f\u8005\u6d3b\u52a8\u548c\u81ea\u5df1\u5f53\u8001\u5e08\u7684\u7406\u60f3\u65f6\u5145\u6ee1\u4e86\u5174\u594b\uff0c\u6210\u5c31\u611f\u548c\u8d23\u4efb\u611f\u3002\u53ef\u4ee5\u770b\u5230\u5979\u975e\u5e38\u5e0c\u671b\u627e\u5230\u4e00\u6761\u6e20\u9053\u6765\u5b9e\u73b0\u81ea\u5df1\u7684\u7406\u60f3\uff0c\u5e76\u4e14\u8fd9\u4e2a\u7406\u60f3\u5bf9\u793e\u4f1a\u662f\u5f88\u6709\u610f\u4e49\u7684\u3002n- \u8be5\u540c\u5b66\u6709\u81ea\u6211\u63d0\u5347\u7684\u6b32\u671b\u548c\u5b66\u4e60\u7684\u80fd\u529b\uff0c\u5979\u5bf9\u81ea\u5df1\u9700\u8981\u63d0\u5347\u7684\u5730\u65b9\u76f8\u5bf9\u6bd4\u8f83\u660e\u786e\uff0c\u5728\u5f88\u591a\u65b9\u9762\u4e5f\u5c55\u73b0\u51fa\u4e0d\u9519\u7684\u4fdd\u6301\u5b66\u4e60\u7684\u80fd\u529bn- \u8be5\u540c\u5b66\u8ba4\u53ef\u5bfc\u5e08\u5236\uff0c\u5979\u591a\u6b21\u63d0\u5230\u4e00\u4e2a\u597d\u8001\u5e08\u7684\u91cd\u8981\u6027\uff0c\u4ee5\u53ca\u5e0c\u671b\u81ea\u5df1\u4ee5\u540e\u7684\u4eba\u751f\u4e2d\u9047\u5230\u4e00\u4f4d\u597d\u5bfc\u5e08nn\u4ee5\u4e0a\u4e09\u70b9\u662f\u6211\u8ba4\u4e3a\u8be5\u540c\u5b66\u80fd\u591f\u901a\u8fc7\u8fdc\u89c1\u5bfc\u5e08\u5236\u6709\u6240\u6536\u83b7\u7684\u57fa\u7840\uff0c\u4e5f\u662f\u8fdc\u89c1\u80fd\u591f\u901a\u8fc7\u901a\u8fc7\u5e2e\u52a9\u8be5\u540c\u5b66\u800c\u60e0\u53ca\u793e\u4f1a\u7684\u57fa\u7840\u3002\u4e0b\u9762\u51e0\u70b9\u662f\u6211\u8ba4\u4e3a\u8fdc\u89c1\u53ef\u4ee5\u5177\u4f53\u5e2e\u52a9\u5230\u8be5\u540c\u5b66\u7684\u5730\u65b9\uff1an- \u603b\u4f53\u6765\u8bf4\uff0c\u8be5\u540c\u5b66\u7684\u516b\u4e2a\u7ef4\u5ea6\u5e76\u4e0d\u5b8c\u7f8e\uff0c\u5728\u67d0\u4e9b\u7ef4\u5ea6\u4e0a\u6709\u6bd4\u8f83\u5927\u7684\u8fdb\u6b65\u7a7a\u95f4n- \u4ece\u2019\u9053\u2018\u7684\u5c42\u9762\u800c\u8a00\uff0c\u8be5\u540c\u5b66\u7f3a\u4e4f\u5bf9\u793e\u4f1a\u73b0\u8c61\u7684\u7cfb\u7edf\u601d\u8003\uff0c\u5979\u5bf9\u8fd9\u4e9b\u95ee\u9898\u7684\u770b\u6cd5\u5f80\u5f80\u5c40\u9650\u5728\u4e2a\u4eba\u7ecf\u5386\u4e0a\u3002\u8fd9\u662f\u8fdc\u89c1\u5e73\u53f0\u53ef\u4ee5\u63d0\u4f9b\u5f88\u591a\u5f15\u5bfc\u7684\u5730\u65b9\u3002\u6211\u76f8\u4fe1\u5982\u679c\u8be5\u540c\u5b66\u80fd\u591f\u7ad9\u5728\u66f4\u9ad8\u7684\u89d2\u5ea6\u601d\u8003\u5979\u7684\u7ecf\u5386\uff0c\u5979\u7684\u8d23\u4efb\u611f\u53ef\u4ee5\u60e0\u53ca\u66f4\u591a\u7684\u4eba\u3002n- \u4ece\u2018\u672f\u2019\u7684\u5c42\u9762\u800c\u8a00\uff0c\u6211\u89c2\u5bdf\u5230\u8be5\u540c\u5b66\u7684\u4fe1\u606f\u6e20\u9053\u76f8\u5bf9\u6bd4\u8f83\u5355\u4e00\uff0c\u5f88\u591a\u4fe1\u606f\u6765\u81ea\u4e8e\u5bfc\u5e08\u548c\u8eab\u8fb9\u7684\u4eba\uff0c\u5bf9\u81ea\u5df1\u7684\u8ba4\u8bc6\u4e5f\u6709\u5f85\u6df1\u5165\u3002\u800c\u8fd9\u4e24\u70b9\u90fd\u662f\u6211\u4eec\u5bfc\u5e08\u5236\u7684\u5f3a\u9879\u3002",
